gradientNoise.fragment:
#version 300 es
precision mediump float;
uniform float u_time;
uniform vec2 u_resolution;
in vec2 v_uv;
out vec4 fragColor;

vec2 random2(vec2 st) {
  st = vec2(dot(st, vec2(127.1, 311.7)), dot(st, vec2(269.5, 183.3)));
  return -1.0 + 2.0 * fract(sin(st) * 43758.5453123);
}

float gradientNoise(vec2 st) {
  vec2 i = floor(st);
  vec2 f = fract(st);
  vec2 u = f * f * (3.0 - 2.0 * f);
  return mix(mix(dot(random2(i + vec2(0,0)), f - vec2(0,0)),
                 dot(random2(i + vec2(1,0)), f - vec2(1,0)), u.x),
             mix(dot(random2(i + vec2(0,1)), f - vec2(0,1)),
                 dot(random2(i + vec2(1,1)), f - vec2(1,1)), u.x), u.y) * 0.5 + 0.5;
}

void main() {
  vec2 st = v_uv * 6.0;
  float n = gradientNoise(st);
  fragColor = vec4(vec3(n), 1.0);
}

