sdfBlend.fragment:
#version 300 es
precision mediump float;
uniform float u_time;
uniform vec2 u_resolution;
in vec2 v_uv;
out vec4 fragColor;

float sdCircle(vec2 p, float r) { return length(p) - r; }

float smin(float a, float b, float k) {
  float h = clamp(0.5 + 0.5 * (b - a) / k, 0.0, 1.0);
  return mix(b, a, h) - k * h * (1.0 - h);
}

void main() {
  vec2 p = (gl_FragCoord.xy * 2.0 - u_resolution) / min(u_resolution.x, u_resolution.y);
  float t = u_time * 0.5;
  vec2 off1 = vec2(sin(t) * 0.3, 0.0);
  vec2 off2 = vec2(-sin(t) * 0.3, 0.0);
  float d = smin(sdCircle(p - off1, 0.25), sdCircle(p - off2, 0.25), 0.15);
  float fill = 1.0 - smoothstep(-0.01, 0.01, d);
  float outline = 1.0 - smoothstep(0.0, 0.02, abs(d));
  vec3 col = fill * vec3(0.8, 0.2, 0.6) + outline * vec3(1.0);
  fragColor = vec4(col, 1.0);
}

