basicRT.fragment:
#version 300 es
precision highp float;
uniform float u_time;
uniform vec2 u_resolution;
in vec2 v_uv;
out vec4 fragColor;

#define MAX_DIST 100.0

struct Material {
  vec3 albedo;
  float roughness;
};

struct Hit {
  float t;
  vec3 position;
  vec3 normal;
  Material material;
};

Hit miss() {
  Hit h;
  h.t = MAX_DIST;
  return h;
}

float intersectSphere(vec3 ro, vec3 rd, vec3 center, float radius) {
  vec3 oc = ro - center;
  float b = dot(oc, rd);
  float c = dot(oc, oc) - radius * radius;
  float h = b * b - c;
  if (h < 0.0) return -1.0;
  return -b - sqrt(h);
}

Hit trace(vec3 ro, vec3 rd) {
  Hit closest = miss();

  Material floorMat;
  floorMat.albedo = vec3(0.8);
  floorMat.roughness = 0.9;

  Material sphere1Mat;
  sphere1Mat.albedo = vec3(0.8, 0.2, 0.2);
  sphere1Mat.roughness = 0.3;

  Material sphere2Mat;
  sphere2Mat.albedo = vec3(0.2, 0.2, 0.8);
  sphere2Mat.roughness = 0.1;

  if (rd.y < 0.0) {
    float floorT = -ro.y / rd.y;
    if (floorT > 0.0 && floorT < closest.t) {
      closest.t = floorT;
      closest.position = ro + rd * floorT;
      closest.normal = vec3(0.0, 1.0, 0.0);
      closest.material = floorMat;
    }
  }

  float t1 = intersectSphere(ro, rd, vec3(-1.0, 0.0, 0.0), 1.0);
  if (t1 > 0.0 && t1 < closest.t) {
    Hit s1;
    s1.t = t1;
    s1.position = ro + rd * t1;
    s1.normal = normalize(s1.position - vec3(-1.0, 0.0, 0.0));
    s1.material = sphere1Mat;
    closest = s1;
  }

  float t2 = intersectSphere(ro, rd, vec3(1.0, 0.0, 0.0), 1.0);
  if (t2 > 0.0 && t2 < closest.t) {
    Hit s2;
    s2.t = t2;
    s2.position = ro + rd * t2;
    s2.normal = normalize(s2.position - vec3(1.0, 0.0, 0.0));
    s2.material = sphere2Mat;
    closest = s2;
  }

  return closest;
}

vec3 shade(Hit hit, vec3 rd) {
  if (hit.t >= MAX_DIST) return vec3(0.05, 0.05, 0.1);

  vec3 lightDir = normalize(vec3(1.0, 2.0, 1.0));
  float diff = max(dot(hit.normal, lightDir), 0.0);
  vec3 viewDir = -rd;
  vec3 halfDir = normalize(lightDir + viewDir);
  float spec = pow(max(dot(hit.normal, halfDir), 0.0), 32.0);

  vec3 ambient = hit.material.albedo * 0.1;
  vec3 diffuse = hit.material.albedo * diff * 0.8;
  vec3 specular = vec3(1.0) * spec * (1.0 - hit.material.roughness);

  return ambient + diffuse + specular;
}

void main() {
  vec2 uv = (gl_FragCoord.xy * 2.0 - u_resolution) / min(u_resolution.x, u_resolution.y);
  vec3 ro = vec3(0.0, 2.0, 5.0);
  vec3 rd = normalize(vec3(uv, -1.5));

  Hit hit = trace(ro, rd);
  vec3 col = shade(hit, rd);

  fragColor = vec4(col, 1.0);
}

