pathTracing.fragment:
#version 300 es
precision highp float;
uniform float u_time;
uniform vec2 u_resolution;
in vec2 v_uv;
out vec4 fragColor;

#define PI 3.14159265359
#define MAX_DIST 100.0

float hash(vec2 p) {
  return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453);
}

vec3 randomDirection(vec2 seed) {
  float z = 1.0 - 2.0 * hash(seed);
  float r = sqrt(max(0.0, 1.0 - z * z));
  float phi = 2.0 * PI * hash(seed + 42.0);
  return vec3(r * cos(phi), r * sin(phi), z);
}

float intersectSphere(vec3 ro, vec3 rd, vec3 center, float radius) {
  vec3 oc = ro - center;
  float b = dot(oc, rd);
  float c = dot(oc, oc) - radius * radius;
  float h = b * b - c;
  if (h < 0.0) return -1.0;
  return -b - sqrt(h);
}

struct Hit {
  float t;
  vec3 position;
  vec3 normal;
  vec3 albedo;
  float emission;
};

Hit traceScene(vec3 ro, vec3 rd) {
  Hit closest;
  closest.t = MAX_DIST;

  if (rd.y < 0.0) {
    float floorT = -ro.y / rd.y;
    if (floorT > 0.0 && floorT < closest.t) {
      closest.t = floorT;
      closest.position = ro + rd * floorT;
      closest.normal = vec3(0.0, 1.0, 0.0);
      closest.albedo = vec3(0.8);
      closest.emission = 0.0;
    }
  }

  float t1 = intersectSphere(ro, rd, vec3(-1.5, 0.0, 0.0), 1.0);
  if (t1 > 0.0 && t1 < closest.t) {
    closest.t = t1;
    closest.position = ro + rd * t1;
    closest.normal = normalize(closest.position - vec3(-1.5, 0.0, 0.0));
    closest.albedo = vec3(0.8, 0.2, 0.2);
    closest.emission = 0.0;
  }

  float t2 = intersectSphere(ro, rd, vec3(1.5, 0.0, 0.0), 1.0);
  if (t2 > 0.0 && t2 < closest.t) {
    closest.t = t2;
    closest.position = ro + rd * t2;
    closest.normal = normalize(closest.position - vec3(1.5, 0.0, 0.0));
    closest.albedo = vec3(0.2, 0.8, 0.2);
    closest.emission = 0.0;
  }

  float tl = intersectSphere(ro, rd, vec3(0.0, 3.0, 0.0), 0.5);
  if (tl > 0.0 && tl < closest.t) {
    closest.t = tl;
    closest.position = ro + rd * tl;
    closest.normal = normalize(closest.position - vec3(0.0, 3.0, 0.0));
    closest.albedo = vec3(1.0);
    closest.emission = 5.0;
  }

  return closest;
}

vec3 pathTrace(vec3 ro, vec3 rd) {
  vec3 throughput = vec3(1.0);
  vec3 emission = vec3(0.0);

  for (int bounce = 0; bounce < 8; bounce++) {
    Hit hit = traceScene(ro, rd);

    if (hit.t >= MAX_DIST) {
      emission += throughput * vec3(0.05, 0.05, 0.1);
      break;
    }

    emission += throughput * hit.albedo * hit.emission;

    vec3 newDir = normalize(hit.normal + randomDirection(gl_FragCoord.xy + float(bounce) * 100.0));
    throughput *= hit.albedo;
    ro = hit.position + hit.normal * 0.01;
    rd = newDir;
  }

  return emission;
}

void main() {
  vec2 uv = (gl_FragCoord.xy * 2.0 - u_resolution) / min(u_resolution.x, u_resolution.y);
  vec3 ro = vec3(0.0, 2.0, 5.0);
  vec3 rd = normalize(vec3(uv, -1.5));

  vec3 col = pathTrace(ro, rd);
  col = col / (col + vec3(1.0));
  col = pow(col, vec3(1.0/2.2));

  fragColor = vec4(col, 1.0);
}

