glass.fragment:
#version 300 es
precision highp float;
uniform float u_time;
uniform vec2 u_resolution;
in vec2 v_uv;
out vec4 fragColor;

#define PI 3.14159265359
#define MAX_DIST 100.0

float hash(vec2 p) {
  return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453);
}

float schlick(float cosine, float ior) {
  float r0 = (1.0 - ior) / (1.0 + ior);
  r0 = r0 * r0;
  return r0 + (1.0 - r0) * pow(clamp(1.0 - cosine, 0.0, 1.0), 5.0);
}

float intersectSphere(vec3 ro, vec3 rd, vec3 center, float radius) {
  vec3 oc = ro - center;
  float b = dot(oc, rd);
  float c = dot(oc, oc) - radius * radius;
  float h = b * b - c;
  if (h < 0.0) return -1.0;
  return -b - sqrt(h);
}

struct Hit {
  float t;
  vec3 position;
  vec3 normal;
  float ior;
};

Hit traceScene(vec3 ro, vec3 rd) {
  Hit closest;
  closest.t = MAX_DIST;
  closest.ior = 1.0;

  if (rd.y < 0.0) {
    float floorT = -ro.y / rd.y;
    if (floorT > 0.0 && floorT < closest.t) {
      closest.t = floorT;
      closest.position = ro + rd * floorT;
      closest.normal = vec3(0.0, 1.0, 0.0);
      closest.ior = 1.0;
    }
  }

  float ts = intersectSphere(ro, rd, vec3(0.0, 0.0, 0.0), 1.0);
  if (ts > 0.0 && ts < closest.t) {
    closest.t = ts;
    closest.position = ro + rd * ts;
    closest.normal = normalize(closest.position - vec3(0.0, 0.0, 0.0));
    closest.ior = 1.5;
  }

  return closest;
}

vec3 tracePath(vec3 ro, vec3 rd) {
  vec3 throughput = vec3(1.0);
  vec3 emission = vec3(0.0);

  for (int bounce = 0; bounce < 8; bounce++) {
    Hit hit = traceScene(ro, rd);

    if (hit.t >= MAX_DIST) {
      emission += throughput * vec3(0.1, 0.1, 0.2);
      break;
    }

    if (hit.ior > 1.0) {
      float cosTheta = dot(-rd, hit.normal);
      float kr = schlick(cosTheta, hit.ior);

      if (hash(gl_FragCoord.xy + float(bounce) * 73.0) < kr) {
        rd = reflect(rd, hit.normal);
      } else {
        vec3 outwardNormal;
        float eta;
        if (cosTheta > 0.0) {
          outwardNormal = -hit.normal;
          eta = 1.0 / hit.ior;
        } else {
          outwardNormal = hit.normal;
          eta = hit.ior;
        }
        rd = refract(rd, outwardNormal, eta);
        if (length(rd) < 0.001) rd = reflect(rd, hit.normal);
      }
      ro = hit.position + rd * 0.01;
    } else {
      vec3 lightDir = normalize(vec3(1.0, 2.0, 1.0));
      float diff = max(dot(hit.normal, lightDir), 0.0);
      emission += throughput * vec3(0.8) * diff;
      throughput *= 0.0;
    }
  }

  return emission;
}

void main() {
  vec2 uv = (gl_FragCoord.xy * 2.0 - u_resolution) / min(u_resolution.x, u_resolution.y);
  vec3 ro = vec3(0.0, 2.0, 5.0);
  vec3 rd = normalize(vec3(uv, -1.5));

  vec3 col = tracePath(ro, rd);
  col = col / (col + vec3(1.0));
  col = pow(col, vec3(1.0/2.2));

  fragColor = vec4(col, 1.0);
}

