kira.fragment:
#version 300 es
precision mediump float;
uniform float u_time;
uniform vec2 u_resolution;
in vec2 v_uv;
out vec4 fragColor;

float random(vec2 st) {
  return fract(sin(dot(st, vec2(12.9898, 78.233))) * 43758.5453);
}

void main() {
  vec2 st = v_uv * 20.0;
  st.y += mod(floor(st.x), 2.0) * 0.5;
  vec2 i_st = floor(st);
  vec2 f_st = fract(st) - 0.5;
  float sparkle = random(i_st + floor(u_time * 2.0));
  sparkle = step(0.92, sparkle);
  float d = length(f_st);
  float shape = sparkle * (1.0 - smoothstep(0.0, 0.2, d));
  float cross = sparkle * (1.0 - smoothstep(0.0, 0.04, min(abs(f_st.x), abs(f_st.y)))) * (1.0 - smoothstep(0.15, 0.2, d));
  float glow = sparkle * 0.15 / max(d, 0.05);
  vec3 col = (shape + cross) * vec3(1.0, 0.95, 0.8) + glow * vec3(0.5, 0.7, 1.0);
  col *= 0.8 + 0.2 * sin(u_time * 3.0 + random(i_st) * 6.28);
  fragColor = vec4(col, 1.0);
}

