poolWater.fragment:
#version 300 es
precision highp float;
uniform float u_time;
uniform vec2 u_resolution;
in vec2 v_uv;
out vec4 fragColor;

vec2 random2(vec2 p) {
  return fract(sin(vec2(dot(p, vec2(127.1, 311.7)), dot(p, vec2(269.5, 183.3)))) * 43758.5453);
}

float voronoi(vec2 st, float time) {
  vec2 i_st = floor(st);
  vec2 f_st = fract(st);
  float min_dist = 10.0;
  for (int y = -1; y <= 1; y++) {
    for (int x = -1; x <= 1; x++) {
      vec2 neighbor = vec2(float(x), float(y));
      vec2 point = random2(i_st + neighbor);
      point = 0.5 + 0.5 * sin(time + 6.2831 * point);
      float d = length(neighbor + point - f_st);
      min_dist = min(min_dist, d);
    }
  }
  return min_dist;
}

void main() {
  vec2 p = (gl_FragCoord.xy * 2.0 - u_resolution) / min(u_resolution.x, u_resolution.y);
  float t = u_time;

  // Wave distortion on UV
  vec2 uv = p * 4.0;
  uv.x += 0.3 * sin(uv.y * 2.0 + t * 0.8);
  uv.y += 0.2 * cos(uv.x * 3.0 + t * 0.6);

  // Multi-layer Voronoi for caustics
  float v1 = voronoi(uv * 1.0, t * 0.5);
  float v2 = voronoi(uv * 2.0 + 3.7, t * 0.7 + 10.0);
  float v3 = voronoi(uv * 4.0 + 7.3, t * 0.3 + 20.0);

  // Caustic pattern - bright edges of Voronoi cells
  float caustic1 = 0.02 / max(abs(v1 - 0.15), 0.005);
  float caustic2 = 0.015 / max(abs(v2 - 0.12), 0.005);
  float caustic3 = 0.01 / max(abs(v3 - 0.10), 0.005);
  float caustics = caustic1 + caustic2 * 0.6 + caustic3 * 0.3;

  // Pool depth gradient - deeper = darker blue
  float depth = 0.5 + 0.5 * p.y;
  vec3 deepColor = vec3(0.02, 0.08, 0.25);
  vec3 shallowColor = vec3(0.1, 0.4, 0.6);
  vec3 poolBase = mix(deepColor, shallowColor, depth * 0.6);

  // Surface highlight - Fresnel-like edge brightening
  float edge = 1.0 - smoothstep(0.0, 1.5, length(p));
  vec3 surfaceHighlight = vec3(0.4, 0.7, 0.9) * edge * 0.3;

  // Combine: base water + caustics + highlight
  vec3 col = poolBase;
  col += vec3(0.3, 0.6, 0.8) * caustics * 0.15;
  col += surfaceHighlight;

  // Subtle surface shimmer
  float shimmer = sin(p.x * 15.0 + t) * sin(p.y * 12.0 + t * 0.7);
  col += vec3(0.05, 0.1, 0.15) * shimmer * 0.3;

  // Tone mapping
  col = col / (col + vec3(1.0));

  fragColor = vec4(col, 1.0);
}
